// Fetch the forecast needed to assess a single route leg's destination.
// Returns Result: { ok: true, data } on success, { ok: false, error: { code, message } } on failure.
//
// Deliberately separate from the shared fetchWeather: it adds daily
// sunrise/sunset (for the after-sunset check), drops the marine wave call
// (irrelevant to leg warnings), and exposes utc_offset_seconds so the caller
// can map local forecast times to UTC. Keeping it separate avoids changing the
// hot fetchWeather path that analyzeDirections calls many times per request.
async function fetchRouteWeather(lat: number, lon: number) {
  try {
    // Conversion factor: meters per second to knots
    const MS_TO_KNOTS = 1.94384;
    // Reuse the app-wide hourly horizon; 3 days of daily data for sun times
    const forecastHours = config.get('DEFAULT_FORECAST_HOURS') || 48;

    // Hourly fields needed by computeLegWarnings
    const hourlyParams = [
      'wind_speed_10m', 'wind_direction_10m', 'wind_gusts_10m',
      'precipitation', 'pressure_msl', 'cloud_cover'
    ].join(',');

    const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}`
      + `&hourly=${hourlyParams}`
      + `&daily=sunrise,sunset`
      + `&wind_speed_unit=ms`
      + `&forecast_hours=${forecastHours}`
      + `&forecast_days=3`
      + `&timezone=auto`;

    const res = await fetch(url);

    // API error — return a Result failure instead of throwing
    if (!res.ok) {
      return {
        ok: false,
        error: { code: 'ROUTE_WEATHER_API_ERROR', message: `Open-Meteo error: ${res.status}` }
      };
    }

    const data = await res.json();

    // Round helper — keep wind speeds to 1 decimal place
    const round1 = (n: number) => Math.round(n * 10) / 10;

    // Build the hourly forecast array with wind speeds converted to knots.
    // Times are LOCAL (timezone=auto); the caller converts using utcOffsetSeconds.
    const h = data.hourly || {};
    const times = h.time || [];
    const hourly = times.map((time: string, i: number) => ({
      time,
      windSpeed: round1((h.wind_speed_10m?.[i] ?? 0) * MS_TO_KNOTS),
      windDirection: h.wind_direction_10m?.[i] ?? null,
      windGusts: round1((h.wind_gusts_10m?.[i] ?? 0) * MS_TO_KNOTS),
      precipitation: h.precipitation?.[i] ?? 0,
      pressure: h.pressure_msl?.[i] ?? null,
      cloudCover: h.cloud_cover?.[i] ?? null
    }));

    // Daily sunrise/sunset arrays (local ISO strings), aligned by daily.time date
    const d = data.daily || {};
    const daily = {
      time: d.time || [],
      sunrise: d.sunrise || [],
      sunset: d.sunset || []
    };

    // Success — wrap payload in Result, exposing the timezone offset for conversion
    return {
      ok: true,
      data: {
        latitude: lat,
        longitude: lon,
        timezone: data.timezone,
        utcOffsetSeconds: data.utc_offset_seconds ?? 0,
        hourly,
        daily
      }
    };
  } catch (err) {
    // Catch unexpected errors (network failures, JSON parse errors, etc.)
    return {
      ok: false,
      error: { code: 'ROUTE_WEATHER_API_ERROR', message: (err as Error).message || 'Unexpected error fetching route weather' }
    };
  }
}
